import { createContext, useContext, useState, useEffect } from 'react';
import { authAPI } from '../api';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  // Restore session
  useEffect(() => {
    const token = localStorage.getItem('sam_token');
    const saved  = localStorage.getItem('sam_user');
    if (token && saved) {
      try { setUser(JSON.parse(saved)); } catch {}
    }
    setLoading(false);
  }, []);

  const login = async (email, password) => {
    try {
      const data = await authAPI.login(email, password);
      localStorage.setItem('sam_token', data.token);
      localStorage.setItem('sam_user', JSON.stringify(data.user));
      // Augment user with display fields
      const u = { ...data.user, initials: data.user.name.split(' ').map(w=>w[0]).join('').toUpperCase().slice(0,2) };
      setUser(u);
      return { ok: true };
    } catch (e) {
      return { ok: false, error: e.message };
    }
  };

  const signup = async (formData) => {
    try {
      const data = await authAPI.signup(formData);
      localStorage.setItem('sam_token', data.token);
      const u = { ...data.user, initials: data.user.name.split(' ').map(w=>w[0]).join('').toUpperCase().slice(0,2) };
      setUser(u);
      return { ok: true };
    } catch (e) {
      return { ok: false, error: e.message };
    }
  };

  const logout = () => {
    localStorage.removeItem('sam_token');
    localStorage.removeItem('sam_user');
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, signup, logout, loading }}>
      {!loading && children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => useContext(AuthContext);
